// Translate Meta's webhook envelope into {from, text} items.
// Interactive button/list taps feed their title back as if typed.
// Status/delivery events (no `messages`) produce no items.
const out = [];
for (const item of $input.all()) {
  const body = item.json.body ?? item.json;
  for (const entry of body?.entry ?? []) {
    for (const change of entry?.changes ?? []) {
      for (const msg of change?.value?.messages ?? []) {
        if (!msg?.from) continue;
        let text = '';
        if (msg.type === 'text' && msg.text?.body) text = msg.text.body;
        else if (msg.type === 'interactive') text = msg.interactive?.button_reply?.title || msg.interactive?.list_reply?.title || '';
        out.push({ json: { from: msg.from, text } });
      }
    }
  }
}
return out;

// Build the Graph API payload: suggestions become native interactive buttons
// (<=3) or a list message (4-10); long bodies or no chips fall back to text.
const reply = $json.reply ?? 'Sorry, something went wrong. Please try again.';
const to = $('Extract Messages').item.json.from;
const chips = ($json.suggestions ?? []).filter(s => s && s.length <= 20).slice(0, 10);
const base = { messaging_product: 'whatsapp', recipient_type: 'individual', to };
let payload;
if (chips.length === 0 || reply.length > 1024) {
  payload = { ...base, type: 'text', text: { body: reply } };
} else if (chips.length <= 3) {
  payload = { ...base, type: 'interactive', interactive: { type: 'button', body: { text: reply }, action: { buttons: chips.map((title, i) => ({ type: 'reply', reply: { id: 'chip_' + i, title } })) } } };
} else {
  payload = { ...base, type: 'interactive', interactive: { type: 'list', body: { text: reply }, action: { button: 'Choose an option', sections: [{ title: 'BlueWings', rows: chips.map((title, i) => ({ id: 'chip_' + i, title })) }] } } };
}
return { json: payload };
